@RestController
@RequestMapping("/api/events")
class EventProducerController {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final HeaderValidator headerValidator;

    public EventProducerController(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
        this.headerValidator = new HeaderValidator();
    }

    @PostMapping("/publish")
    public ResponseEntity<Map<String, Object>> publishEvent(@RequestBody EventRequest eventRequest) {
        try {
            headerValidator.validateHeaders(eventRequest.getHeaders());
            
            ProducerRecord<String, String> record = createProducerRecord(
                eventRequest.getTopic(),
                eventRequest.getKey(),
                eventRequest.getMessage(),
                eventRequest.getHeaders()
            );

            RecordMetadata metadata = kafkaTemplate.send(record).get().getRecordMetadata();

            Map<String, Object> response = new HashMap<>();
            response.put("status", "success");
            response.put("topic", metadata.topic());
            response.put("partition", metadata.partition());
            response.put("offset", metadata.offset());
            response.put("timestamp", metadata.timestamp());

            return ResponseEntity.ok(response);
        } catch (ValidationException e) {
            Map<String, Object> errorResponse = new HashMap<>();
            errorResponse.put("status", "error");
            errorResponse.put("message", e.getMessage());
            return ResponseEntity.badRequest().body(errorResponse);
        } catch (InterruptedException | ExecutionException e) {
            Map<String, Object> errorResponse = new HashMap<>();
            errorResponse.put("status", "error");
            errorResponse.put("message", "Failed to publish message: " + e.getMessage());
            return ResponseEntity.internalServerError().body(errorResponse);
        }
    }

    private ProducerRecord<String, String> createProducerRecord(
            String topic, String key, String message, Map<String, String> headers) {
        
        List<Header> kafkaHeaders = new ArrayList<>();
        
        if (headers != null) {
            for (Map.Entry<String, String> entry : headers.entrySet()) {
                String sanitizedKey = headerValidator.sanitizeHeaderKey(entry.getKey());
                String sanitizedValue = headerValidator.sanitizeHeaderValue(entry.getValue());
                kafkaHeaders.add(new RecordHeader(sanitizedKey, 
                    sanitizedValue.getBytes(StandardCharsets.UTF_8)));
            }
        }

        ProducerRecord<String, String> record = new ProducerRecord<>(topic, null, key, message);
        kafkaHeaders.forEach(header -> record.headers().add(header));
        
        return record;
    }
}

